  createStreamErrorHandler,
  endActiveSpan,
  getErrorMessage,
  logAgentError,
  observe,
  updateAgentObservation,
  updateAgentTrace,
} from "./middleware";

// Prompts
export {
  main_agent_prompt,
  manual_mode_agent_prompt,
  vision_prompt,
} from "./prompts";

